### 3. **Missing Authentication & Authorization (OWASP A07:2021 – Identification and Authentication Failures)**

**Issue:** Both endpoints are publicly accessible without any authentication mechanism.

**Recommendation - Add authentication for sensitive endpoints:**
```javascript
const jwt = require('jsonwebtoken');

// Middleware for token verification
const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1]; // Bearer TOKEN

  if (!token) {
    return res.status(401).json({ error: 'Access token required' });
  }

  jwt.verify(token, process.env.ACCESS_TOKEN_SECRET, (err, user) => {
    if (err) return res.status(403).json({ error: 'Invalid token' });
    req.user = user;
    next();
  });
};

// Protect sensitive endpoint
app.get('/users', authenticateToken, (req, res) => {
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});
```

